// ─── Types ────────────────────────────────────────────────────────────────────

export interface PaymentInput {
  amount: number;
  currency: string;
  userId: string;
  // additional fields as needed by domain
  [key: string]: unknown;
}

export interface FraudCheckResult {
  isFraudulent: boolean;
}

export interface FraudService {
  check(input: PaymentInput): Promise<FraudCheckResult>;
}

export interface ChargeResult {
  success: boolean;
  transactionId?: string;
  declineReason?: string;
}

export interface PaymentGateway {
  charge(input: PaymentInput): Promise<ChargeResult>;
}

export interface PaymentResult {
  success: true;
  transaction_id: string;
}

// ─── Error codes ──────────────────────────────────────────────────────────────

export type PaymentErrorCode =
  | "FRAUD_DETECTED"
  | "PAYMENT_DECLINED"
  | "FRAUD_SERVICE_UNAVAILABLE"
  | "GATEWAY_UNAVAILABLE";

export class PaymentError extends Error {
  readonly code: PaymentErrorCode;
  readonly cause?: unknown;

  constructor(code: PaymentErrorCode, message: string, cause?: unknown) {
    super(message);
    this.name = "PaymentError";
    this.code = code;
    this.cause = cause;
  }
}

// ─── Implementation ───────────────────────────────────────────────────────────

export async function processPayment(
  input: PaymentInput,
  fraudService: FraudService,
  gateway: PaymentGateway
): Promise<PaymentResult> {
  // Step 1: Fraud check
  let fraudResult: FraudCheckResult;
  try {
    fraudResult = await fraudService.check(input);
  } catch (err) {
    throw new PaymentError(
      "FRAUD_SERVICE_UNAVAILABLE",
      "Fraud check service is unavailable",
      err
    );
  }

  // AC2 / AC6: Fraud flagged — do NOT call gateway
  if (fraudResult.isFraudulent) {
    throw new PaymentError("FRAUD_DETECTED", "Payment flagged as fraudulent");
  }

  // Step 2: Charge via payment gateway
  let chargeResult: ChargeResult;
  try {
    chargeResult = await gateway.charge(input);
  } catch (err) {
    throw new PaymentError(
      "GATEWAY_UNAVAILABLE",
      "Payment gateway is unavailable",
      err
    );
  }

  // AC3: Gateway returned a decline
  if (!chargeResult.success) {
    throw new PaymentError(
      "PAYMENT_DECLINED",
      chargeResult.declineReason ?? "Payment was declined"
    );
  }

  // AC1: All good
  return {
    success: true,
    transaction_id: chargeResult.transactionId!,
  };
}

